async function loadData() {
  try {
    const res = await fetch('/api/data', {
      signal: controller.signal,
    });
    const data = await res.json();
    console.log('\u6570\u636E\uFF1A', data);
  } catch (err) {
    if (err.name === 'AbortError') {
      console.log('\u8BF7\u6C42\u88AB\u53D6\u6D88');
    } else {
      console.error('\u8BF7\u6C42\u5931\u8D25\uFF1A', err);
    }
  }
}

// \u67D0\u4E2A\u65F6\u523B\u4E0D\u60F3\u7B49\u4E86\uFF1A
